// app/(admin)/settings/page.tsx
'use client';

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { zodResolver } from '@hookform/resolvers/zod';
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  CardFooter,
} from '@/components/ui/Card';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Switch } from '@/components/ui/switch';
import { Button } from '@/components/ui/button';
import {
  Search,
  User,
  Edit,
  Trash,
  Lock,
  LockOpen,
  ChevronDown,
  ChevronUp,
  Settings,
  UserPlus,
  Download,
  Check,
  X,
  Settings2,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { useToast } from '@/hooks/use-toast';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';

// تعريف مخطط Zod لنموذج المستخدم
const userSchema = z.object({
  id: z.string(),
  name: z.string().min(2, 'يجب أن يكون الاسم مكون من حرفين على الأقل'),
  email: z.string().email('بريد إلكتروني غير صالح'),
  role: z.enum(['student', 'host', 'admin']),
  status: z.enum(['active', 'disabled']),
  joinDate: z.string(),
});

type User = z.infer<typeof userSchema>;

const AdminSettingsPage = () => {
  const { toast } = useToast();
  const [users, setUsers] = useState<User[]>([]);
  const [filteredUsers, setFilteredUsers] = useState<User[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [roleFilter, setRoleFilter] = useState<string>('all');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [sortField, setSortField] = useState<keyof User>('name');
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('asc');
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [userToDelete, setUserToDelete] = useState<User | null>(null);
  const [isBulkEditing, setIsBulkEditing] = useState(false);
  const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
  const [systemSettings, setSystemSettings] = useState({
    emailNotifications: true,
    darkMode: false,
    autoSave: true,
  });
  const [pendingHosts, setPendingHosts] = useState(
    [
      { id: 'h1', name: 'أكاديمية المستقبل', email: 'host1@university.edu', requestedAt: '2024-12-01' },
      { id: 'h2', name: 'مركز الفعاليات', email: 'host2@university.edu', requestedAt: '2024-12-03' },
    ] as { id: string; name: string; email: string; requestedAt: string }[]
  );

  // تهيئة react-hook-form
  const form = useForm<User>({
    resolver: zodResolver(userSchema),
    defaultValues: {
      id: '',
      name: '',
      email: '',
      role: 'student',
      status: 'active',
      joinDate: '',
    },
  });

  // جلب بيانات المستخدمين (محاكاة)
  useEffect(() => {
    const fetchUsers = async () => {
      try {
        setIsLoading(true);
        // محاكاة جلب البيانات من API
        const mockUsers: User[] = [
          {
            id: '1',
            name: 'علي أحمد',
            email: 'ali.ahmed@university.edu',
            role: 'student',
            status: 'active',
            joinDate: '2023-01-15',
          },
          {
            id: '2',
            name: 'سارة محمد',
            email: 'sara.mohammed@university.edu',
            role: 'student',
            status: 'active',
            joinDate: '2023-02-20',
          },
          {
            id: '3',
            name: 'محمد خالد',
            email: 'mohammed.khaled@university.edu',
            role: 'host',
            status: 'active',
            joinDate: '2022-11-05',
          },
          {
            id: '4',
            name: 'فاطمة حسن',
            email: 'fatima.hassan@university.edu',
            role: 'host',
            status: 'disabled',
            joinDate: '2022-09-12',
          },
          {
            id: '5',
            name: 'أحمد علي',
            email: 'ahmed.ali@university.edu',
            role: 'admin',
            status: 'active',
            joinDate: '2021-08-30',
          },
          {
            id: '6',
            name: 'نورا سعيد',
            email: 'nora.saeed@university.edu',
            role: 'host',
            status: 'active',
            joinDate: '2023-03-18',
          },
          {
            id: '7',
            name: 'يوسف كمال',
            email: 'youssef.kamal@university.edu',
            role: 'student',
            status: 'disabled',
            joinDate: '2023-04-22',
          },
          {
            id: '8',
            name: 'ليلى عبدالله',
            email: 'layla.abdullah@university.edu',
            role: 'host',
            status: 'active',
            joinDate: '2022-12-10',
          },
        ];

        // إضافة تأخير لمحاكاة جلب البيانات
        await new Promise((resolve) => setTimeout(resolve, 800));

        setUsers(mockUsers);
        setFilteredUsers(mockUsers);
      } catch (error) {
        toast({
          title: 'خطأ في جلب البيانات',
          description: 'حدث خطأ أثناء محاولة جلب بيانات المستخدمين',
          variant: 'destructive',
        });
      } finally {
        setIsLoading(false);
      }
    };

    fetchUsers();
  }, []);

  // تطبيق الفلاتر والبحث
  useEffect(() => {
    let result = [...users];

    // تطبيق بحث البريد الإلكتروني
    if (searchTerm) {
      result = result.filter(
        (user) =>
          user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
          user.name.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // تطبيق فلتر الدور
    if (roleFilter !== 'all') {
      result = result.filter((user) => user.role === roleFilter);
    }

    // تطبيق فلتر الحالة
    if (statusFilter !== 'all') {
      result = result.filter((user) => user.status === statusFilter);
    }

    // تطبيق الترتيب
    result.sort((a, b) => {
      if (a[sortField] < b[sortField]) return sortDirection === 'asc' ? -1 : 1;
      if (a[sortField] > b[sortField]) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });

    setFilteredUsers(result);
  }, [users, searchTerm, roleFilter, statusFilter, sortField, sortDirection]);

  // معالجة تغيير الترتيب
  const handleSort = (field: keyof User) => {
    if (sortField === field) {
      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
    } else {
      setSortField(field);
      setSortDirection('asc');
    }
  };

  // فتح نموذج التعديل
  const handleEdit = (user: User) => {
    form.reset(user);
    setEditingUser(user);
    setIsEditModalOpen(true);
  };

  // إغلاق نموذج التعديل
  const handleCloseEditModal = () => {
    setIsEditModalOpen(false);
    setEditingUser(null);
    form.reset();
  };

  // معالجة تحديث المستخدم
  const handleUpdateUser = async (data: User) => {
    try {
      // محاكاة تحديث المستخدم في الخادم
      await new Promise((resolve) => setTimeout(resolve, 500));

      setUsers((prevUsers) =>
        prevUsers.map((user) => (user.id === data.id ? data : user))
      );

      toast({
        title: 'تم التحديث بنجاح',
        description: 'تم تحديث بيانات المستخدم بنجاح',
        className: 'bg-green-600 text-white border-0',
      });

      handleCloseEditModal();
    } catch (error) {
      toast({
        title: 'خطأ في التحديث',
        description: 'حدث خطأ أثناء محاولة تحديث بيانات المستخدم',
        variant: 'destructive',
      });
    }
  };

  // فتح نموذج الحذف
  const handleDelete = (user: User) => {
    setUserToDelete(user);
    setIsDeleteModalOpen(true);
  };

  // معالجة حذف المستخدم
  const handleConfirmDelete = async () => {
    if (!userToDelete) return;

    try {
      // محاكاة حذف المستخدم في الخادم
      await new Promise((resolve) => setTimeout(resolve, 500));

      setUsers((prevUsers) =>
        prevUsers.filter((user) => user.id !== userToDelete.id)
      );

      toast({
        title: 'تم الحذف بنجاح',
        description: 'تم حذف المستخدم بنجاح',
        className: 'bg-green-600 text-white border-0',
      });

      setIsDeleteModalOpen(false);
      setUserToDelete(null);
    } catch (error) {
      toast({
        title: 'خطأ في الحذف',
        description: 'حدث خطأ أثناء محاولة حذف المستخدم',
        variant: 'destructive',
      });
    }
  };

  // تبديل حالة المستخدم
  const handleToggleStatus = async (user: User) => {
    try {
      const newStatus = user.status === 'active' ? 'disabled' : 'active';

      // محاكاة تحديث حالة المستخدم في الخادم
      await new Promise((resolve) => setTimeout(resolve, 300));

      setUsers((prevUsers) =>
        prevUsers.map((u) =>
          u.id === user.id ? { ...u, status: newStatus } : u
        )
      );

      toast({
        title: `تم ${newStatus === 'active' ? 'تفعيل' : 'تعطيل'} الحساب`,
        description: `تم تغيير حالة المستخدم بنجاح`,
        className: 'bg-green-600 text-white border-0',
      });
    } catch (error) {
      toast({
        title: 'خطأ في التحديث',
        description: 'حدث خطأ أثناء محاولة تغيير حالة المستخدم',
        variant: 'destructive',
      });
    }
  };

  // عرض أيقونة الترتيب
  const renderSortIcon = (field: keyof User) => {
    if (sortField !== field) return null;
    return sortDirection === 'asc' ? (
      <ChevronUp size={16} />
    ) : (
      <ChevronDown size={16} />
    );
  };

  // عرض شارة الدور
  const renderRoleBadge = (role: User['role']) => {
    const roleConfig = {
      student: { label: 'طالب', color: 'bg-blue-100 text-blue-800' },
      host: { label: 'مضيف', color: 'bg-purple-100 text-purple-800' },
      admin: { label: 'مشرف', color: 'bg-amber-100 text-amber-800' },
    };

    return (
      <Badge className={cn('px-3 py-1 rounded-full', roleConfig[role].color)}>
        {roleConfig[role].label}
      </Badge>
    );
  };

  // عرض شارة الحالة
  const renderStatusBadge = (status: User['status']) => {
    return status === 'active' ? (
      <Badge className='bg-green-100 text-green-800 px-3 py-1 rounded-full'>
        نشط
      </Badge>
    ) : (
      <Badge className='bg-gray-100 text-gray-800 px-3 py-1 rounded-full'>
        معطل
      </Badge>
    );
  };

  // توليد الأحرف الأولى من الاسم
  const getInitials = (name: string) => {
    const names = name.split(' ');
    return names.map((n) => n[0]).join('');
  };

  // تبديل إعدادات النظام
  const handleSystemSettingChange = (setting: keyof typeof systemSettings) => {
    setSystemSettings((prev) => ({
      ...prev,
      [setting]: !prev[setting],
    }));

    toast({
      title: 'تم تحديث الإعدادات',
      description: `تم ${systemSettings[setting] ? 'تعطيل' : 'تفعيل'} ${
        setting === 'emailNotifications'
          ? 'الإشعارات'
          : setting === 'darkMode'
          ? 'الوضع الليلي'
          : 'الحفظ التلقائي'
      }`,
      className: 'bg-blue-600 text-white border-0',
    });
  };

  // التبديل بين تحرير المجموعة
  const toggleBulkEditing = () => {
    setIsBulkEditing(!isBulkEditing);
    setSelectedUsers([]);
  };

  // تحديد/إلغاء تحديد مستخدم
  const toggleUserSelection = (userId: string) => {
    setSelectedUsers((prev) =>
      prev.includes(userId)
        ? prev.filter((id) => id !== userId)
        : [...prev, userId]
    );
  };

  // تحديد/إلغاء تحديد الكل
  const toggleSelectAll = () => {
    if (selectedUsers.length === filteredUsers.length) {
      setSelectedUsers([]);
    } else {
      setSelectedUsers(filteredUsers.map((user) => user.id));
    }
  };

  // تطبيق الحالة على المستخدمين المحددين
  const applyStatusToSelected = (status: 'active' | 'disabled') => {
    setUsers((prevUsers) =>
      prevUsers.map((user) =>
        selectedUsers.includes(user.id) ? { ...user, status } : user
      )
    );

    toast({
      title: 'تم تحديث المستخدمين',
      description: `تم تغيير حالة ${selectedUsers.length} مستخدمين`,
      className: 'bg-green-600 text-white border-0',
    });

    setSelectedUsers([]);
    setIsBulkEditing(false);
  };

  const approveHost = (id: string) => {
    setPendingHosts((prev) => prev.filter((h) => h.id !== id));
    toast({ title: 'تمت الموافقة', description: 'تمت الموافقة على المضيف', className: 'bg-green-600 text-white border-0' });
  };

  const rejectHost = (id: string) => {
    setPendingHosts((prev) => prev.filter((h) => h.id !== id));
    toast({ title: 'تم الرفض', description: 'تم رفض طلب المضيف', variant: 'destructive' });
  };

  return (
    <div className='min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 p-6'>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className='max-w-7xl mx-auto'
      >
        <div className='grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8'>
          {/* العنوان والإحصاءات */}
          <motion.div
            className='lg:col-span-2 bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl shadow-xl p-6 text-white'
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.1 }}
          >
            <div className='flex items-center justify-between'>
              <div>
                <h1 className='text-2xl font-bold flex items-center gap-3'>
                  <Settings
                    className='text-white'
                    size={28}
                  />
                  لوحة تحكم المشرفين
                </h1>
                <p className='mt-2 opacity-90'>
                  إدارة المستخدمين والإعدادات النظامية
                </p>
              </div>
              <Avatar className='border-2 border-white'>
                <AvatarFallback className='bg-indigo-700'>SA</AvatarFallback>
              </Avatar>
            </div>

            <div className='grid grid-cols-3 gap-4 mt-8'>
              <div className='bg-white/10 p-4 rounded-lg'>
                <p className='text-sm opacity-80'>المستخدمون</p>
                <p className='text-2xl font-bold mt-1'>{users.length}</p>
              </div>
              <div className='bg-white/10 p-4 rounded-lg'>
                <p className='text-sm opacity-80'>النشطون</p>
                <p className='text-2xl font-bold mt-1'>
                  {users.filter((u) => u.status === 'active').length}
                </p>
              </div>
              <div className='bg-white/10 p-4 rounded-lg'>
                <p className='text-sm opacity-80'>المشرفون</p>
                <p className='text-2xl font-bold mt-1'>
                  {users.filter((u) => u.role === 'admin').length}
                </p>
              </div>
            </div>
          </motion.div>

          {/* إعدادات النظام */}
          <motion.div
            className='bg-white rounded-2xl shadow-xl p-6'
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.2 }}
          >
            <h2 className='text-lg font-bold text-gray-800 mb-4 flex items-center gap-2'>
              <Settings
                size={20}
                className='text-indigo-600'
              />
              إعدادات النظام
            </h2>

            <div className='space-y-4'>
              <div className='flex items-center justify-between'>
                <div>
                  <Label className='font-medium text-gray-700'>
                    الإشعارات البريدية
                  </Label>
                  <p className='text-sm text-gray-500'>
                    إرسال إشعارات عبر البريد الإلكتروني
                  </p>
                </div>
                <Switch
                  checked={systemSettings.emailNotifications}
                  onCheckedChange={() =>
                    handleSystemSettingChange('emailNotifications')
                  }
                />
              </div>

              <div className='flex items-center justify-between'>
                <div>
                  <Label className='font-medium text-gray-700'>
                    الوضع الليلي
                  </Label>
                  <p className='text-sm text-gray-500'>
                    تفعيل الوضع المظلم للنظام
                  </p>
                </div>
                <Switch
                  checked={systemSettings.darkMode}
                  onCheckedChange={() => handleSystemSettingChange('darkMode')}
                />
              </div>

              <div className='flex items-center justify-between'>
                <div>
                  <Label className='font-medium text-gray-700'>
                    الحفظ التلقائي
                  </Label>
                  <p className='text-sm text-gray-500'>
                    حفظ التغييرات تلقائياً
                  </p>
                </div>
                <Switch
                  checked={systemSettings.autoSave}
                  onCheckedChange={() => handleSystemSettingChange('autoSave')}
                />
              </div>
            </div>
          </motion.div>
        </div>

        {/* بطاقة إدارة المستخدمين */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
          className='bg-white rounded-2xl shadow-xl overflow-hidden'
        >
          <CardHeader className='border-b border-gray-200'>
            <div className='flex flex-col md:flex-row md:items-center justify-between gap-4'>
              <CardTitle className='flex items-center gap-2 text-xl'>
                <Settings2 className='text-indigo-600' size={24} />
                الموافقات للمضيفين
              </CardTitle>
            </div>
          </CardHeader>
          <CardContent className='p-6'>
            {pendingHosts.length === 0 ? (
              <div className='text-center text-gray-500 py-8'>لا توجد طلبات حالية</div>
            ) : (
              <div className='space-y-4'>
                {pendingHosts.map((host) => (
                  <div key={host.id} className='flex items-center justify-between p-4 rounded-xl border border-gray-200'>
                    <div className='flex items-center gap-4'>
                      <Avatar>
                        <AvatarFallback className='bg-indigo-100 text-indigo-700'>
                          {getInitials(host.name)}
                        </AvatarFallback>
                      </Avatar>
                      <div>
                        <p className='font-medium text-gray-900'>{host.name}</p>
                        <p className='text-sm text-gray-500'>{host.email}</p>
                      </div>
                    </div>
                    <div className='flex items-center gap-2 text-sm text-gray-500'>
                      <span>تاريخ الطلب:</span>
                      <span className='font-medium'>{host.requestedAt}</span>
                    </div>
                    <div className='flex items-center gap-2'>
                      <Button onClick={() => approveHost(host.id)} className='bg-green-600 hover:bg-green-700 text-white'>
                        <Check className='h-4 w-4 mr-2' /> موافقة
                      </Button>
                      <Button variant='outline' onClick={() => rejectHost(host.id)} className='text-red-600 hover:bg-red-50'>
                        <X className='h-4 w-4 mr-2' /> رفض
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.35 }}
          className='bg-white rounded-2xl shadow-xl overflow-hidden mt-6'
        >
          <CardHeader className='border-b border-gray-200'>
            <div className='flex flex-col md:flex-row md:items-center justify-between gap-4'>
              <CardTitle className='flex items-center gap-2 text-xl'>
                <User className='text-indigo-600' size={24} />
                إدارة المستخدمين
              </CardTitle>
              <div className='flex flex-col sm:flex-row gap-3 w-full md:w-auto'>
                <div className='relative flex-1'>
                  <Search className='absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 h-4 w-4' />
                  <input
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    placeholder='ابحث بالاسم أو البريد'
                    className='w-full rounded-lg border border-gray-300 pr-9 pl-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500'
                  />
                </div>
                <select
                  className='rounded-lg border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500'
                  value={roleFilter}
                  onChange={(e) => setRoleFilter(e.target.value)}
                >
                  <option value='all'>كل الأدوار</option>
                  <option value='student'>طالب</option>
                  <option value='host'>مضيف</option>
                  <option value='admin'>مشرف</option>
                </select>
                <select
                  className='rounded-lg border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500'
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                >
                  <option value='all'>كل الحالات</option>
                  <option value='active'>نشط</option>
                  <option value='disabled'>معطل</option>
                </select>
                <div className='flex items-center gap-2'>
                  <Button variant='outline' onClick={toggleBulkEditing}>
                    {isBulkEditing ? 'إنهاء التحديد' : 'تحديد متعدد'}
                  </Button>
                  {isBulkEditing && (
                    <>
                      <Button variant='outline' onClick={toggleSelectAll}>تحديد الكل</Button>
                      <Button className='bg-green-600 hover:bg-green-700 text-white' onClick={() => applyStatusToSelected('active')}>
                        تفعيل المحددين
                      </Button>
                      <Button variant='outline' className='text-red-600 hover:bg-red-50' onClick={() => applyStatusToSelected('disabled')}>
                        تعطيل المحددين
                      </Button>
                    </>
                  )}
                </div>
              </div>
            </div>
          </CardHeader>
          <CardContent className='p-0'>
            <div className='overflow-x-auto'>
              <table className='min-w-full divide-y divide-gray-200'>
                <thead className='bg-gray-50'>
                  <tr>
                    {isBulkEditing && <th className='px-4 py-3 text-right text-xs font-medium text-gray-500'>تحديد</th>}
                    <th className='px-6 py-3 text-right text-xs font-medium text-gray-500 cursor-pointer' onClick={() => handleSort('name')}>
                      الاسم
                      <span className='inline-block ml-1 align-middle'>{renderSortIcon('name' as keyof User)}</span>
                    </th>
                    <th className='px-6 py-3 text-right text-xs font-medium text-gray-500 cursor-pointer' onClick={() => handleSort('email')}>
                      البريد الإلكتروني
                      <span className='inline-block ml-1 align-middle'>{renderSortIcon('email' as keyof User)}</span>
                    </th>
                    <th className='px-6 py-3 text-right text-xs font-medium text-gray-500'>الدور</th>
                    <th className='px-6 py-3 text-right text-xs font-medium text-gray-500'>الحالة</th>
                    <th className='px-6 py-3 text-right text-xs font-medium text-gray-500'>إجراءات</th>
                  </tr>
                </thead>
                <tbody className='bg-white divide-y divide-gray-200'>
                  {filteredUsers.map((user) => (
                    <tr key={user.id} className='hover:bg-gray-50'>
                      {isBulkEditing && (
                        <td className='px-4 py-3'>
                          <input
                            type='checkbox'
                            checked={selectedUsers.includes(user.id)}
                            onChange={() => toggleUserSelection(user.id)}
                            className='h-4 w-4 accent-indigo-600'
                          />
                        </td>
                      )}
                      <td className='px-6 py-4 whitespace-nowrap'>
                        <div className='flex items-center gap-3'>
                          <Avatar>
                            <AvatarFallback className='bg-purple-100 text-purple-700'>
                              {getInitials(user.name)}
                            </AvatarFallback>
                          </Avatar>
                          <div>
                            <div className='font-medium text-gray-900'>{user.name}</div>
                            <div className='text-xs text-gray-500'>انضم: {user.joinDate}</div>
                          </div>
                        </div>
                      </td>
                      <td className='px-6 py-4 whitespace-nowrap text-gray-700'>{user.email}</td>
                      <td className='px-6 py-4 whitespace-nowrap'>{renderRoleBadge(user.role)}</td>
                      <td className='px-6 py-4 whitespace-nowrap'>{renderStatusBadge(user.status)}</td>
                      <td className='px-6 py-4 whitespace-nowrap'>
                        <div className='flex items-center gap-2'>
                          <Button variant='outline' size='sm' onClick={() => handleEdit(user)}>
                            <Edit className='h-4 w-4 mr-1' /> تعديل
                          </Button>
                          <Button
                            variant='outline'
                            size='sm'
                            onClick={() => handleToggleStatus(user)}
                            className={user.status === 'active' ? 'text-red-600 hover:bg-red-50' : 'text-green-600 hover:bg-green-50'}
                          >
                            {user.status === 'active' ? (
                              <>
                                <Lock className='h-4 w-4 mr-1' /> تعطيل
                              </>
                            ) : (
                              <>
                                <LockOpen className='h-4 w-4 mr-1' /> تفعيل
                              </>
                            )}
                          </Button>
                          <Button variant='destructive' size='sm' onClick={() => handleDelete(user)}>
                            <Trash className='h-4 w-4 mr-1' /> حذف
                          </Button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </motion.div>
      </motion.div>
    </div>
  );
};

export default AdminSettingsPage;
